30	export function buildPatchCacheKey(patch: string, scope = "diff-panel"): string {
31	  const normalizedPatch = patch.trim();
32	  const primary = fnv1a32(normalizedPatch, FNV_OFFSET_BASIS_32, FNV_PRIME_32).toString(36);
33	  const secondary = fnv1a32(
34	    normalizedPatch,
35	    SECONDARY_HASH_SEED,
36	    SECONDARY_HASH_MULTIPLIER,
37	  ).toString(36);
38	  return `${scope}:${normalizedPatch.length}:${primary}:${secondary}`;
39	}
