## Implementation Plan: Custom Theme System for T3 Code

### Overview

This plan adds a 3-theme custom system (t3-dark, t3-light, t3-midnight) replacing the old light/dark/system radio buttons. The work touches 5 files: 1 new shared package file, 1 modified shared package manifest, and 3 web app files (the hook replacement, a new selector component, and the settings route).

---

### Step 1: Create `packages/shared/src/theme.ts`

This is a new file. It must use only plain TypeScript (no Effect Schema, no `@t3tools/contracts`) because the shared package's Effect dependency is present but the theme module is web-only; keeping it dependency-free avoids pulling node-specific Effect code into the browser bundle.

**Full contents:**

```ts
// packages/shared/src/theme.ts

export type ThemeId = "t3-dark" | "t3-light" | "t3-midnight";

export interface ThemeColors {
  background: string;
  foreground: string;
  accent: string;
  primary: string;
  ring: string;
  sidebarBg: string;
  editorBg: string;
  terminalBg: string;
  statusBarBg: string;
}

export interface AppTheme {
  id: ThemeId;
  label: string;
  dark: boolean;
  colors: ThemeColors;
}

export const BUILT_IN_THEMES: Record<ThemeId, AppTheme> = {
  "t3-dark": {
    id: "t3-dark",
    label: "Dark",
    dark: true,
    colors: {
      background: "#0f0f10",
      foreground: "#f5f5f5",
      accent: "oklch(0.588 0.217 264)",
      primary: "oklch(0.588 0.217 264)",
      ring: "oklch(0.588 0.217 264)",
      sidebarBg: "#111113",
      editorBg: "#0a0a0b",
      terminalBg: "#0a0a0b",
      statusBarBg: "#1e1e22",
    },
  },
  "t3-light": {
    id: "t3-light",
    label: "Light",
    dark: false,
    colors: {
      background: "#ffffff",
      foreground: "#262626",
      accent: "oklch(0.488 0.217 264)",
      primary: "oklch(0.488 0.217 264)",
      ring: "oklch(0.488 0.217 264)",
      sidebarBg: "#f9fafb",
      editorBg: "#ffffff",
      terminalBg: "#1c1c1c",
      statusBarBg: "#1f2937",
    },
  },
  "t3-midnight": {
    id: "t3-midnight",
    label: "Midnight",
    dark: true,
    colors: {
      background: "#000000",
      foreground: "#e5e5e5",
      accent: "#a78bfa",
      primary: "#a78bfa",
      ring: "#a78bfa",
      sidebarBg: "#050507",
      editorBg: "#000000",
      terminalBg: "#020204",
      statusBarBg: "#0f0f12",
    },
  },
};

export const THEME_IDS = Object.keys(BUILT_IN_THEMES) as ThemeId[];

export const DEFAULT_THEME_ID: ThemeId = "t3-dark";

export function isThemeId(value: unknown): value is ThemeId {
  return typeof value === "string" && value in BUILT_IN_THEMES;
}
```

**Key decisions:**
- `primary` mirrors `accent` for each theme so the blue/violet Tailwind `--primary` class-based utilities continue working.
- `ring` mirrors `accent` for the same reason (focus rings use `--ring`).
- `isThemeId` is a plain type guard — no Schema dependency — so it can be used safely in both the hook and a hypothetical server context.
- `dark: boolean` on each theme drives `resolvedTheme` computation and `.dark` class toggling.

---

### Step 2: Add the `./theme` subpath export to `packages/shared/package.json`

**Current `exports` block** (lines 6–27 of `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775494179307-6dojan/packages/shared/package.json`):

```json
"exports": {
  "./model": { "types": "./src/model.ts", "import": "./src/model.ts" },
  "./git":   { ... },
  "./logging": { ... },
  "./shell": { ... },
  "./Net":   { ... }
}
```

**Add one entry** immediately after the `"./Net"` entry:

```json
"./theme": {
  "types": "./src/theme.ts",
  "import": "./src/theme.ts"
}
```

The pattern `"types": "./src/theme.ts", "import": "./src/theme.ts"` is identical to every other export in this file — no build step, the Bundler `moduleResolution` in `tsconfig.base.json` resolves directly to TypeScript source.

---

### Step 3: Replace `apps/web/src/hooks/useTheme.ts`

This is a complete file replacement. The module-level store pattern (`useSyncExternalStore` + module-level listeners array) is preserved from the original; only the stored value type and DOM-mutation logic change.

**Full contents:**

```ts
// apps/web/src/hooks/useTheme.ts

import { createElement, type ReactNode, useCallback, useEffect, useSyncExternalStore } from "react";
import {
  BUILT_IN_THEMES,
  DEFAULT_THEME_ID,
  isThemeId,
  type AppTheme,
  type ThemeId,
} from "@t3tools/shared/theme";

// ── Storage ───────────────────────────────────────────────────────────────────

const STORAGE_KEY = "t3code:theme";

function migrateStoredValue(raw: string | null): ThemeId {
  // Old values: "system" | "dark" → t3-dark; "light" → t3-light; invalid → DEFAULT
  if (raw === "light") return "t3-light";
  if (raw === "dark" || raw === "system") return "t3-dark";
  if (isThemeId(raw)) return raw;
  return DEFAULT_THEME_ID;
}

function getStored(): ThemeId {
  if (typeof localStorage === "undefined") return DEFAULT_THEME_ID;
  return migrateStoredValue(localStorage.getItem(STORAGE_KEY));
}

// ── DOM Application ───────────────────────────────────────────────────────────

const CSS_PROP_MAP: Array<[keyof AppTheme["colors"], string]> = [
  ["background",   "--background"],
  ["foreground",   "--foreground"],
  ["primary",      "--primary"],
  ["ring",         "--ring"],
  ["sidebarBg",    "--sidebar-bg"],
  ["editorBg",     "--editor-bg"],
  ["terminalBg",   "--terminal-bg"],
  ["statusBarBg",  "--status-bar-bg"],
];

function applyTheme(themeId: ThemeId, suppressTransitions = false): void {
  const theme = BUILT_IN_THEMES[themeId];
  const root = document.documentElement;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  // 1. Set / clear .dark class for Tailwind compatibility
  root.classList.toggle("dark", theme.dark);

  // 2. Inject inline custom properties (highest specificity — overrides stylesheet)
  for (const [colorKey, cssVar] of CSS_PROP_MAP) {
    root.style.setProperty(cssVar, theme.colors[colorKey]);
  }

  // 3. color-scheme for browser chrome (scrollbars, form controls)
  root.style.setProperty("color-scheme", theme.dark ? "dark" : "light");

  if (suppressTransitions) {
    // Force reflow before removing the class
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load — prevents flash before React hydrates
applyTheme(getStored());

// ── External Store ─────────────────────────────────────────────────────────────

let listeners: Array<() => void> = [];
let lastThemeId: ThemeId | null = null;

function emitChange(): void {
  for (const listener of listeners) listener();
}

function getSnapshot(): ThemeId {
  const id = getStored();
  // Referential stability: reuse previous value if equal
  if (lastThemeId === id) return lastThemeId;
  lastThemeId = id;
  return id;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Cross-tab sync
  const handleStorage = (e: StorageEvent): void => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ── Hook ───────────────────────────────────────────────────────────────────────

export function useTheme() {
  const themeId = useSyncExternalStore(subscribe, getSnapshot);
  const theme = BUILT_IN_THEMES[themeId];
  const resolvedTheme: "light" | "dark" = theme.dark ? "dark" : "light";

  const setThemeId = useCallback((next: ThemeId): void => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount (handles SSR/hydration edge cases)
  useEffect(() => {
    applyTheme(themeId);
  }, [themeId]);

  return { themeId, theme, setThemeId, resolvedTheme } as const;
}

// ── ThemeProvider ──────────────────────────────────────────────────────────────

interface ThemeProviderProps {
  children?: ReactNode;
}

export function ThemeProvider({ children }: ThemeProviderProps) {
  // Calling useTheme() here ensures the DOM-sync effects run regardless of
  // whether any consumer is mounted. No React Context overhead.
  useTheme();
  return createElement(Fragment, null, children);
}
```

**Important notes:**
- The `Fragment` import: `createElement` with `Fragment` needs `import { Fragment } from "react"`. Add `Fragment` to the react import at the top.
- `ThemeProvider` is a thin wrapper — it does NOT create a React Context. Its sole purpose is ensuring `useEffect(() => { applyTheme(themeId); }, [themeId])` fires on every render tree, even when `useTheme()` isn't called deeper in the tree.
- The `CSS_PROP_MAP` array approach avoids repetition and makes it straightforward to add or remove CSS properties in the future.
- The old `systemDark` / media-query listener is removed — the new system has no "system" option.
- `getSnapshot()` maintains referential stability using the `lastThemeId` variable — same pattern as the original `lastSnapshot` variable.

---

### Step 4: Add `ThemeProvider` to `apps/web/src/router.ts`

**Current Wrap chain** (lines 19–24):

```ts
Wrap: ({ children }) =>
  createElement(
    QueryClientProvider,
    { client: queryClient },
    createElement(StoreProvider, null, children),
  ),
```

**Modified Wrap chain** — add `ThemeProvider` as the outermost wrapper so it mounts once per app lifetime, before any route components:

```ts
import { ThemeProvider } from "./hooks/useTheme";

// ...inside getRouter:
Wrap: ({ children }) =>
  createElement(
    ThemeProvider,
    null,
    createElement(
      QueryClientProvider,
      { client: queryClient },
      createElement(StoreProvider, null, children),
    ),
  ),
```

`ThemeProvider` wraps the outermost level so its `useEffect` runs once during initial mount and again on theme changes, regardless of route. This ensures `applyTheme` is always re-synchronized if React ever re-renders the root without the module-level initialization path running.

---

### Step 5: Create `apps/web/src/components/ThemeSelector.tsx`

This is a new file. It replaces the radio-button group in the settings page.

```tsx
// apps/web/src/components/ThemeSelector.tsx

import { BUILT_IN_THEMES, THEME_IDS, type ThemeId } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";
import { cn } from "../lib/utils";

export function ThemeSelector() {
  const { themeId: activeId, setThemeId } = useTheme();

  return (
    <div
      className="grid grid-cols-3 gap-3"
      role="radiogroup"
      aria-label="Theme selection"
    >
      {THEME_IDS.map((id) => {
        const theme = BUILT_IN_THEMES[id];
        const isActive = id === activeId;
        const c = theme.colors;

        return (
          <button
            key={id}
            type="button"
            role="radio"
            aria-checked={isActive}
            onClick={() => setThemeId(id)}
            className={cn(
              "relative flex flex-col overflow-hidden rounded-xl border-2 text-left transition-all",
              isActive
                ? "border-primary shadow-sm"
                : "border-border hover:border-border/60",
            )}
          >
            {/* Mini UI mockup preview */}
            <div
              className="flex h-20 w-full overflow-hidden"
              aria-hidden="true"
            >
              {/* Sidebar strip */}
              <div
                className="w-8 shrink-0 border-r"
                style={{
                  backgroundColor: c.sidebarBg,
                  borderColor: "rgba(128,128,128,0.15)",
                }}
              />

              {/* Main content area */}
              <div
                className="flex flex-1 flex-col"
                style={{ backgroundColor: c.background }}
              >
                {/* Editor area */}
                <div
                  className="flex-1"
                  style={{ backgroundColor: c.editorBg }}
                />
                {/* Terminal strip */}
                <div
                  className="h-5 border-t"
                  style={{
                    backgroundColor: c.terminalBg,
                    borderColor: "rgba(128,128,128,0.12)",
                  }}
                />
                {/* Status bar strip */}
                <div
                  className="h-2"
                  style={{ backgroundColor: c.statusBarBg }}
                />
              </div>
            </div>

            {/* Label row */}
            <div
              className="flex items-center justify-between px-2 py-1.5"
              style={{
                backgroundColor: c.background,
                borderTop: "1px solid rgba(128,128,128,0.12)",
              }}
            >
              <span
                className="text-xs font-medium"
                style={{ color: c.foreground }}
              >
                {theme.label}
              </span>

              {isActive && (
                <span
                  className="rounded px-1 py-px text-[9px] font-semibold uppercase tracking-wide"
                  style={{
                    backgroundColor: `${c.accent}22`,
