```ts
// packages/shared/src/theme.ts

export type ThemeId = "t3-dark" | "t3-light" | "t3-midnight";

export interface ThemeColors {
  background: string;
  foreground: string;
  accent: string;
  primary: string;
  ring: string;
  sidebarBg: string;
  editorBg: string;
  terminalBg: string;
  statusBarBg: string;
}

export interface AppTheme {
  id: ThemeId;
  label: string;
  dark: boolean;
  colors: ThemeColors;
}

export const BUILT_IN_THEMES: Record<ThemeId, AppTheme> = {
  "t3-dark": {
    id: "t3-dark",
    label: "Dark",
    dark: true,
    colors: {
      background: "#0f0f10",
      foreground: "#f5f5f5",
      accent: "oklch(0.588 0.217 264)",
      primary: "oklch(0.588 0.217 264)",
      ring: "oklch(0.588 0.217 264)",
      sidebarBg: "#111113",
      editorBg: "#0a0a0b",
      terminalBg: "#0a0a0b",
      statusBarBg: "#1e1e22",
    },
  },
  "t3-light": {
    id: "t3-light",
    label: "Light",
    dark: false,
    colors: {
      background: "#ffffff",
      foreground: "#262626",
      accent: "oklch(0.488 0.217 264)",
      primary: "oklch(0.488 0.217 264)",
      ring: "oklch(0.488 0.217 264)",
      sidebarBg: "#f9fafb",
      editorBg: "#ffffff",
      terminalBg: "#1c1c1c",
      statusBarBg: "#1f2937",
    },
  },
  "t3-midnight": {
    id: "t3-midnight",
    label: "Midnight",
    dark: true,
    colors: {
      background: "#000000",
      foreground: "#e5e5e5",
      accent: "#a78bfa",
      primary: "#a78bfa",
      ring: "#a78bfa",
      sidebarBg: "#050507",
      editorBg: "#000000",
      terminalBg: "#020204",
      statusBarBg: "#0f0f12",
    },
  },
};

export const THEME_IDS = Object.keys(BUILT_IN_THEMES) as ThemeId[];

export const DEFAULT_THEME_ID: ThemeId = "t3-dark";

export function isThemeId(value: unknown): value is ThemeId {
