### Step 3: Replace `apps/web/src/hooks/useTheme.ts`

This is a complete file replacement. The module-level store pattern (`useSyncExternalStore` + module-level listeners array) is preserved from the original; only the stored value type and DOM-mutation logic change.

**Full contents:**

```ts
// apps/web/src/hooks/useTheme.ts

import { createElement, type ReactNode, useCallback, useEffect, useSyncExternalStore } from "react";
import {
  BUILT_IN_THEMES,
  DEFAULT_THEME_ID,
  isThemeId,
  type AppTheme,
  type ThemeId,
} from "@t3tools/shared/theme";

// ── Storage ───────────────────────────────────────────────────────────────────

const STORAGE_KEY = "t3code:theme";

function migrateStoredValue(raw: string | null): ThemeId {
  // Old values: "system" | "dark" → t3-dark; "light" → t3-light; invalid → DEFAULT
  if (raw === "light") return "t3-light";
  if (raw === "dark" || raw === "system") return "t3-dark";
  if (isThemeId(raw)) return raw;
  return DEFAULT_THEME_ID;
}

function getStored(): ThemeId {
  if (typeof localStorage === "undefined") return DEFAULT_THEME_ID;
  return migrateStoredValue(localStorage.getItem(STORAGE_KEY));
}

// ── DOM Application ───────────────────────────────────────────────────────────

const CSS_PROP_MAP: Array<[keyof AppTheme["colors"], string]> = [
  ["background",   "--background"],
  ["foreground",   "--foreground"],
  ["primary",      "--primary"],
  ["ring",         "--ring"],
  ["sidebarBg",    "--sidebar-bg"],
  ["editorBg",     "--editor-bg"],
  ["terminalBg",   "--terminal-bg"],
  ["statusBarBg",  "--status-bar-bg"],
];

function applyTheme(themeId: ThemeId, suppressTransitions = false): void {
  const theme = BUILT_IN_THEMES[themeId];
  const root = document.documentElement;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  // 1. Set / clear .dark class for Tailwind compatibility
  root.classList.toggle("dark", theme.dark);

  // 2. Inject inline custom properties (highest specificity — overrides stylesheet)
  for (const [colorKey, cssVar] of CSS_PROP_MAP) {
    root.style.setProperty(cssVar, theme.colors[colorKey]);
  }

  // 3. color-scheme for browser chrome (scrollbars, form controls)
  root.style.setProperty("color-scheme", theme.dark ? "dark" : "light");

  if (suppressTransitions) {
    // Force reflow before removing the class
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load — prevents flash before React hydrates
applyTheme(getStored());

// ── External Store ─────────────────────────────────────────────────────────────

let listeners: Array<() => void> = [];
let lastThemeId: ThemeId | null = null;

function emitChange(): void {
  for (const listener of listeners) listener();
}

function getSnapshot(): ThemeId {
  const id = getStored();
  // Referential stability: reuse previous value if equal
  if (lastThemeId === id) return lastThemeId;
  lastThemeId = id;
  return id;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Cross-tab sync
  const handleStorage = (e: StorageEvent): void => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ── Hook ───────────────────────────────────────────────────────────────────────

export function useTheme() {
  const themeId = useSyncExternalStore(subscribe, getSnapshot);
  const theme = BUILT_IN_THEMES[themeId];
  const resolvedTheme: "light" | "dark" = theme.dark ? "dark" : "light";

  const setThemeId = useCallback((next: ThemeId): void => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount (handles SSR/hydration edge cases)
  useEffect(() => {
    applyTheme(themeId);
  }, [themeId]);

  return { themeId, theme, setThemeId, resolvedTheme } as const;
}

// ── ThemeProvider ──────────────────────────────────────────────────────────────

interface ThemeProviderProps {
  children?: ReactNode;
}

export function ThemeProvider({ children }: ThemeProviderProps) {
  // Calling useTheme() here ensures the DOM-sync effects run regardless of
  // whether any consumer is mounted. No React Context overhead.
  useTheme();
  return createElement(Fragment, null, children);
}
```

**Important notes:**
- The `Fragment` import: `createElement` with `Fragment` needs `import { Fragment } from "react"`. Add `Fragment` to the react import at the top.
- `ThemeProvider` is a thin wrapper — it does NOT create a React Context. Its sole purpose is ensuring `useEffect(() => { applyTheme(themeId); }, [themeId])` fires on every render tree, even when `useTheme()` isn't called deeper in the tree.
- The `CSS_PROP_MAP` array approach avoids repetition and makes it straightforward to add or remove CSS properties in the future.
- The old `systemDark` / media-query listener is removed — the new system has no "system" option.
- `getSnapshot()` maintains referential stability using the `lastThemeId` variable — same pattern as the original `lastSnapshot` variable.

