import { BUILT_IN_THEMES, THEME_IDS } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";
import { cn } from "../lib/utils";

/**
 * Card-based theme selector with mini UI preview swatches.
 * Each card renders a scaled-down layout (sidebar / editor / terminal / status bar)
 * using inline background colors sourced directly from the theme definition, so all
 * three cards always display their own palette regardless of the currently active theme.
 */
export function ThemeSelector() {
  const { themeId: activeId, setThemeId } = useTheme();

  return (
    <div className="grid grid-cols-3 gap-3" role="radiogroup" aria-label="Theme selection">
      {THEME_IDS.map((id) => {
        const theme = BUILT_IN_THEMES[id];
        const isActive = id === activeId;
        const c = theme.colors;

        return (
          <button
            key={id}
            type="button"
            role="radio"
            aria-checked={isActive}
            onClick={() => setThemeId(id)}
            className={cn(
              "relative flex flex-col overflow-hidden rounded-xl border-2 text-left transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
              isActive
                ? "border-primary shadow-sm"
                : "border-border hover:border-border/60",
            )}
          >
            {/* Mini UI mockup preview */}
            <div className="flex h-20 w-full overflow-hidden" aria-hidden="true">
              {/* Sidebar strip */}
              <div
                className="w-8 shrink-0 border-r"
                style={{
                  backgroundColor: c.sidebarBg,
                  borderColor: "rgba(128,128,128,0.15)",
                }}
              />

              {/* Main content column */}
              <div
                className="flex flex-1 flex-col"
                style={{ backgroundColor: c.background }}
              >
                {/* Editor area */}
                <div className="flex-1" style={{ backgroundColor: c.editorBg }} />

                {/* Terminal strip */}
                <div
                  className="h-5 border-t"
                  style={{
                    backgroundColor: c.terminalBg,
                    borderColor: "rgba(128,128,128,0.12)",
                  }}
                />

                {/* Status bar strip */}
                <div className="h-2" style={{ backgroundColor: c.statusBarBg }} />
              </div>
            </div>

            {/* Label row */}
            <div
              className="flex items-center justify-between px-2 py-1.5"
              style={{
                backgroundColor: c.background,
                borderTop: "1px solid rgba(128,128,128,0.12)",
              }}
            >
              <span
                className="text-xs font-medium"
                style={{ color: c.foreground }}
              >
                {theme.label}
              </span>

              {isActive && (
                <span
                  className="rounded px-1 py-px text-[9px] font-semibold uppercase tracking-wide"
                  style={{
                    backgroundColor: `${c.accent}22`,
                    color: c.accent,
                  }}
                >
                  Active
                </span>
              )}
            </div>
          </button>
        );
      })}
    </div>
  );
}

